    int n, m, t;
    scanf("%d %d %d", &n, &m, &t);
    long long ways = 0;
    int a = 4;
    int b = t - a;
    while (a <= n && b != 0) {
        if (b <= m) {
            ways += ncr(n, a) * ncr(m, b);
        }
        a = a + 1;
        b = t - a;
    }
    printf("%lld\n", ways);
    return 0;
}
